import ExcelJS from "exceljs";

/**
 * JSON 데이터를 엑셀 파일로 생성하여 다운로드합니다.
 * @param data 내보낼 데이터 배열 (JSON)
 * @param fileName 저장될 파일명 (확장자 제외)
 * @param sheetName 시트명 (기본값: 'Sheet1')
 */
export async function exportToExcel(data: any[], fileName: string, sheetName: string = "Sheet1") {
  if (!data || data.length === 0) {
    console.error("Export failed: No data provided");
    return;
  }

  try {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet(sheetName);

    // 1. 헤더 추출 (첫 번째 객체의 키 기준)
    const headers = Object.keys(data[0]);
    
    // 2. 컬럼 설정 (헤더 및 폭)
    worksheet.columns = headers.map(key => ({
      header: key.toUpperCase(),
      key: key,
      width: 20
    }));

    // 3. 헤더 스타일 적용
    const headerRow = worksheet.getRow(1);
    headerRow.font = { bold: true, color: { argb: "FFFFFFFF" } };
    headerRow.fill = {
      type: "pattern",
      pattern: "solid",
      fgColor: { argb: "FF4F81BD" }
    };
    headerRow.alignment = { vertical: "middle", horizontal: "center" };

    // 4. 데이터 추가
    worksheet.addRows(data);

    // 5. 모든 셀에 테두리 추가 및 정렬
    worksheet.eachRow((row, rowNumber) => {
      row.eachCell((cell) => {
        cell.border = {
          top: { style: "thin" },
          left: { style: "thin" },
          bottom: { style: "thin" },
          right: { style: "thin" }
        };
        if (rowNumber > 1) {
          cell.alignment = { vertical: "middle", horizontal: "left", wrapText: true };
        }
      });
    });

    // 6. 파일 저장 (브라우저 다운로드)
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const url = window.URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `${fileName}_${new Date().getTime()}.xlsx`;
    anchor.click();
    window.URL.revokeObjectURL(url);
    
    return true;
  } catch (error) {
    console.error("Excel Export Error:", error);
    return false;
  }
}
